DEMO_SOURCE = '// ─── Variables & Types ──────────────────────────────────\nlet x = 10;\nconst y = 20;\nvar z = x + y;\nconsole.log("x + y =", z);\n\nlet name = "World";\nconsole.log("Hello, " + name + "!");\n\nlet arr = [1, 2, 3, 4, 5];\nconsole.log("Array:", arr.join(", "));\nconsole.log("Length:", arr.length);\n\nlet obj = { a: 1, b: "two", c: [3, 4] };\nconsole.log("obj.a =", obj.a, "obj.b =", obj.b);\n\n// ─── Control Flow ───────────────────────────────────────\nfor (let i = 0; i < 5; i++) {\n    if (i === 3) continue;\n    console.log("for loop i:", i);\n}\n\nlet n = 0;\nwhile (n < 3) {\n    console.log("while n:", n);\n    n++;\n}\n\nlet result = x > 5 ? "big" : "small";\nconsole.log("ternary:", result);\n\nswitch (z) {\n    case 20:\n        console.log("z is 20");\n        break;\n    case 30:\n        console.log("z is 30");\n        break;\n    default:\n        console.log("z is something else");\n}\n\n// ─── Functions & Closures ───────────────────────────────\nfunction add(a, b) {\n    return a + b;\n}\nconsole.log("add(3, 4) =", add(3, 4));\n\nfunction makeCounter() {\n    let count = 0;\n    return function() {\n        count++;\n        return count;\n    };\n}\nlet counter = makeCounter();\nconsole.log("counter:", counter(), counter(), counter());\n\nconst square = x => x * x;\nconsole.log("square(5) =", square(5));\n\nconst mul = (a, b) => a * b;\nconsole.log("mul(3, 7) =", mul(3, 7));\n\n// ─── Higher-order functions ─────────────────────────────\nlet nums = [5, 3, 8, 1, 9, 2];\nlet doubled = nums.map(n => n * 2);\nconsole.log("doubled:", doubled.join(", "));\n\nlet evens = nums.filter(n => n % 2 === 0);\nconsole.log("evens:", evens.join(", "));\n\nlet sum = nums.reduce((acc, n) => acc + n, 0);\nconsole.log("sum:", sum);\n\n// ─── String methods ─────────────────────────────────────\nlet s = "  Hello, JavaScript!  ";\nconsole.log("trim:", s.trim());\nconsole.log("upper:", s.trim().toUpperCase());\nconsole.log("split:", "a-b-c-d".split("-").join("|"));\nconsole.log("replace:", "foo-bar-foo".replace("foo", "baz"));\nconsole.log("slice:", "abcdef".slice(1, 4));\n\n// ─── Math ───────────────────────────────────────────────\nconsole.log("Math.PI:", Math.PI);\nconsole.log("Math.sqrt(144):", Math.sqrt(144));\nconsole.log("Math.floor(3.7):", Math.floor(3.7));\nconsole.log("Math.max(1,5,3):", Math.max(1, 5, 3));\n\n// ─── typeof ─────────────────────────────────────────────\nconsole.log("typeof 42:", typeof 42);\nconsole.log("typeof \'hi\':", typeof "hi");\nconsole.log("typeof null:", typeof null);\nconsole.log("typeof undefined:", typeof undefined);\nconsole.log("typeof []:", typeof []);\nconsole.log("typeof add:", typeof add);\n\n// ─── try / catch ────────────────────────────────────────\ntry {\n    throw "Something went wrong!";\n} catch (e) {\n    console.log("Caught:", e);\n}\n\n// ─── Object.keys / Object.values ────────────────────────\nlet person = { name: "Alice", age: 30, city: "NYC" };\nconsole.log("keys:", Object.keys(person).join(", "));\nconsole.log("values:", Object.values(person).join(", "));\n\n// ─── parseInt / parseFloat ──────────────────────────────\nconsole.log("parseInt(\'42\'):", parseInt("42"));\nconsole.log("parseInt(\'ff\', 16):", parseInt("ff", 16));\nconsole.log("parseFloat(\'3.14\'):", parseFloat("3.14"));\n\n// ─── JSON ───────────────────────────────────────────────\nlet data = { x: 1, y: [2, 3] };\nlet jsonStr = JSON.stringify(data);\nconsole.log("JSON:", jsonStr);\nlet parsed = JSON.parse(jsonStr);\nconsole.log("parsed.x:", parsed.x);\n\n// ─── Recursion ──────────────────────────────────────────\nfunction fib(n) {\n    if (n <= 1) return n;\n    return fib(n - 1) + fib(n - 2);\n}\nconsole.log("fib(10) =", fib(10));\n\n// ─── Nested closures ───────────────────────────────────\nfunction outer(a) {\n    return function(b) {\n        return function(c) {\n            return a + b + c;\n        };\n    };\n}\nconsole.log("nested closure:", outer(1)(2)(3));\n\n// ─── Array extras ───────────────────────────────────────\nlet data2 = [1, 2, 3, 4, 5, 6];\nconsole.log("some > 5:", data2.some(n => n > 5));\nconsole.log("every > 0:", data2.every(n => n > 0));\nconsole.log("find > 3:", data2.find(n => n > 3));\nconsole.log("includes 3:", data2.includes(3));\nconsole.log("indexOf 4:", data2.indexOf(4));\n\n// ─── Spread operator ───────────────────────────────────\nlet a1 = [1, 2, 3];\nlet a2 = [...a1, 4, 5];\nconsole.log("spread:", a2.join(", "));\n\nlet obj1 = { a: 1, b: 2 };\nlet obj2 = { ...obj1, c: 3 };\nconsole.log("spread obj:", JSON.stringify(obj2));\n'
